module multi_pipe_4bit (
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);

    localparam SIZE = 4;

    wire [3:0] mul_a_ext, mul_b_ext;
    wire [7:0] partial_products [SIZE-1:0];
    reg [7:0] regs [SIZE-1:0];
    integer i;

    assign mul_a_ext = {4{mul_a}};
    assign mul_b_ext = {4{mul_b}};

    genvar j;
        for (j = 0; j < SIZE; j = j + 1) begin : gen_partial_products
            end // Auto-repaired
            assign partial_products[j] = (mul_b_ext[j]) ? (mul_a_ext << j) : 8'd0;
        end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < SIZE; i = i + 1) begin
                regs[i] <= 8'd0;
            end
        end else begin
            for (i = 0; i < SIZE; i = i + 1) begin
                regs[i] <= regs[i] + partial_products[i];
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 8'd0;
        end else begin
            mul_out <= regs[SIZE-1];
        end
    end

endmodule
